from pathlib import Path
import json,os,re
out=Path(r"Z:\FOXAI\System\EngineeringWorkshop\missions\ENG-20260722-062243-69C555_V1B1A_R2_MINIMAL_LOAD_RESOURCE_BASELINE")
documents=[json.loads(p.read_text(encoding="utf-8")) for p in sorted(out.iterdir()) if p.is_file()]
payloads=[p.read_bytes() for p in sorted(out.iterdir()) if p.is_file()]
roots=[]
for key in ("USERPROFILE","HOME"):
 value=os.environ.get(key)
 if value and len(value.rstrip("\\/"))>=3: roots.append(value.rstrip("\\/"))
usernames=[]
for key in ("USERNAME","USER"):
 value=os.environ.get(key)
 if value and len(value)>=2: usernames.append(value)
def walk(value,path=()):
 if isinstance(value,dict):
  for key,item in value.items(): yield from walk(item,path+(key,))
 elif isinstance(value,list):
  for index,item in enumerate(value): yield from walk(item,path+(index,))
 elif isinstance(value,str): yield path,value
def process_name_path(path): return bool(path) and str(path[-1]) in {"name","process_name","owning_process_name"}
for document in documents:
 for path,text in walk(document):
  folded=text.casefold()
  for root in roots:
   for variant in {root,root.replace("\\","/"),root.replace("/","\\")}:
    assert variant.casefold() not in folded,(path,"profile_root")
  assert re.search(r"(?i)[A-Za-z]:[\\/]+Users[\\/]+(?!<REDACTED_PROFILE(?:_ROOT|_NAME)?>)[^\\/\s\"']+",text) is None,(path,"windows_profile_path")
  for username in usernames:
   assert text.casefold()!=username.casefold(),(path,"exact_profile_name")
   if not process_name_path(path):
    pattern=rf"(?i)(?<![A-Za-z0-9_]){re.escape(username)}(?![A-Za-z0-9_])"
    assert re.search(pattern,text) is None,(path,"profile_name_token")
joined=b"\n".join(payloads); lower=joined.lower()
