 assert token not in lower,token
assert b"k:\\" not in lower and b"k:/" not in lower
for data in payloads: assert b"\r" not in data
receipt=next(doc for doc in documents if doc.get("schema","").endswith("minimal_load_capture_receipt.v1"))
